const MQL4 = {
  generate(bot) {
    const c = bot.configuration;
    return `//+------------------------------------------------------------------+
//| ${bot.name}.mq4                                                   |
//| Generated by VANTIS AI                                             |
//+------------------------------------------------------------------+

#property strict
#property description "${bot.name} - ${c.strategy} strategy"
#property version   "1.00"

// --- Input Parameters ---
input double RiskPerTrade      = ${c.moneyManagement.riskPerTrade};
input double MaxDailyLoss      = ${c.moneyManagement.maxDailyLoss};
input double MaxDailyProfit    = ${c.moneyManagement.maxDailyProfit};
input double FixedLotSize      = ${c.moneyManagement.lotSize};
input int    StopLoss          = ${c.tradeManagement.stopLoss};
input int    TakeProfit        = ${c.tradeManagement.takeProfit};
input bool   UseTrailing       = ${c.tradeManagement.trailingStop.enabled};
input int    TrailingPoints    = ${c.tradeManagement.trailingStop.points};
input string TradingSymbol     = "${c.symbol}";
input int    MagicNumber       = 202401;

// --- Globals ---
double g_dailyProfit = 0;
double g_dailyLoss   = 0;
int    g_ticket      = 0;

//+------------------------------------------------------------------+
//| Expert initialization function                                   |
//+------------------------------------------------------------------+
int OnInit() {
   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
//| Expert deinitialization function                                 |
//+------------------------------------------------------------------+
void OnDeinit(const int reason) {
}

//+------------------------------------------------------------------+
//| Expert tick function                                             |
//+------------------------------------------------------------------+
void OnTick() {
   if (!IsNewBar()) return;

   UpdateDailyPL();

   if (g_dailyLoss >= MaxDailyLoss || g_dailyProfit >= MaxDailyProfit) {
      Comment("Daily limit reached");
      return;
   }

   ${this.generateStrategy(c)}
}

//+------------------------------------------------------------------+
//| Strategy Implementation                                          |
//+------------------------------------------------------------------+
${this.getStrategyFunctions(c)}

//+------------------------------------------------------------------+
//| Helper: Check if new bar                                         |
//+------------------------------------------------------------------+
bool IsNewBar() {
   static datetime lastBar = 0;
   datetime curBar = iTime(Symbol(), PERIOD_CURRENT, 0);
   if (lastBar != curBar) {
      lastBar = curBar;
      return true;
   }
   return false;
}

//+------------------------------------------------------------------+
//| Helper: Update daily profit/loss                                 |
//+------------------------------------------------------------------+
void UpdateDailyPL() {
   g_dailyProfit = 0;
   g_dailyLoss   = 0;
   for (int i = 0; i < OrdersTotal(); i++) {
      if (OrderSelect(i, SELECT_BY_POS, MODE_TRADES)) {
         if (OrderMagicNumber() == MagicNumber && OrderSymbol() == Symbol()) {
            if (OrderProfit() > 0) g_dailyProfit += OrderProfit();
            else g_dailyLoss += MathAbs(OrderProfit());
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Helper: Calculate lot size                                       |
//+------------------------------------------------------------------+
double CalculateLot() {
   double lot = FixedLotSize;
   double minLot = SymbolInfoDouble(Symbol(), SYMBOL_VOLUME_MIN);
   double maxLot = SymbolInfoDouble(Symbol(), SYMBOL_VOLUME_MAX);
   double step  = SymbolInfoDouble(Symbol(), SYMBOL_VOLUME_STEP);
   lot = MathMax(minLot, MathMin(maxLot, lot));
   lot = MathRound(lot / step) * step;
   return lot;
}
`;
  },

  generateStrategy(config) {
    switch (config.strategy) {
      case 'grid': return this.gridEntry(config);
      case 'martingale': return this.martingaleEntry(config);
      case 'hedging': return this.hedgingEntry(config);
      case 'trend': return this.trendEntry(config);
      case 'scalping': return this.scalpingEntry(config);
      default: return this.gridEntry(config);
    }
  },

  getStrategyFunctions(config) {
    switch (config.strategy) {
      case 'grid': return this.gridFunctions();
      case 'martingale': return this.martingaleFunctions();
      case 'hedging': return this.hedgingFunctions();
      case 'trend': return this.trendFunctions();
      case 'scalping': return this.scalpingFunctions();
      default: return this.gridFunctions();
    }
  },

  gridEntry(config) {
    return `
   // Grid Trading Entry
   double gridStep  = ${config.grid.gridStep} * Point;
   double gridLevels = ${config.grid.gridLevels};
   double orderCount = CountOpenOrders();

   if (orderCount < gridLevels) {
      double lot = CalculateLot();
      int ticket = OrderSend(Symbol(), OP_BUY, lot, Ask, 10, Ask - StopLoss * Point, Ask + TakeProfit * Point, "Grid Buy", MagicNumber, 0, clrGreen);
      if (ticket > 0) {
         ticket = OrderSend(Symbol(), OP_SELL, lot, Bid, 10, Bid + StopLoss * Point, Bid - TakeProfit * Point, "Grid Sell", MagicNumber, 0, clrRed);
      }
   }
`;
  },

  gridFunctions() {
    return `
//+------------------------------------------------------------------+
//| Count open orders                                                |
//+------------------------------------------------------------------+
int CountOpenOrders() {
   int count = 0;
   for (int i = 0; i < OrdersTotal(); i++) {
      if (OrderSelect(i, SELECT_BY_POS, MODE_TRADES)) {
         if (OrderMagicNumber() == MagicNumber && OrderSymbol() == Symbol())
            count++;
      }
   }
   return count;
}
`;
  },

  martingaleEntry(config) {
    return `
   // Martingale Entry
   double lot = CalculateLot();
   int lastTicket = GetLastTicket();

   if (CountOpenOrders() == 0) {
      int ticket = OrderSend(Symbol(), OP_BUY, lot, Ask, 10, Ask - StopLoss * Point, Ask + TakeProfit * Point, "Martingale", MagicNumber, 0, clrBlue);
   } else {
      if (lastTicket > 0 && OrderSelect(lastTicket, SELECT_BY_TICKET)) {
         if (OrderProfit() < 0) {
            lot = NormalizeDouble(OrderLots() * ${config.moneyManagement.martingaleMultiplier}, 2);
            lot = MathMin(lot, SymbolInfoDouble(Symbol(), SYMBOL_VOLUME_MAX));
            int ticket = OrderSend(Symbol(), OP_BUY, lot, Ask, 10, Ask - StopLoss * Point, Ask + TakeProfit * Point, "Martingale", MagicNumber, 0, clrBlue);
         }
      }
   }
`;
  },

  martingaleFunctions() {
    return `
//+------------------------------------------------------------------+
//| Get last ticket                                                  |
//+------------------------------------------------------------------+
int GetLastTicket() {
   int ticket = -1;
   datetime t = 0;
   for (int i = OrdersTotal() - 1; i >= 0; i--) {
      if (OrderSelect(i, SELECT_BY_POS, MODE_TRADES)) {
         if (OrderMagicNumber() == MagicNumber && OrderSymbol() == Symbol() && OrderOpenTime() > t) {
            t = OrderOpenTime();
            ticket = OrderTicket();
         }
      }
   }
   return ticket;
}
`;
  },

  hedgingEntry(config) {
    return `
   // Hedging Entry
   double lot = CalculateLot();
   int buyCount = CountOrdersByType(OP_BUY);
   int sellCount = CountOrdersByType(OP_SELL);

   if (buyCount == 0 && sellCount == 0) {
      OrderSend(Symbol(), OP_BUY, lot, Ask, 10, Ask - StopLoss * Point, Ask + TakeProfit * Point, "Hedge Buy", MagicNumber, 0, clrGreen);
   }

   if (buyCount > 0 && sellCount == 0) {
      OrderSend(Symbol(), OP_SELL, lot, Bid, 10, Bid + StopLoss * Point, Bid - TakeProfit * Point, "Hedge Sell", MagicNumber, 0, clrRed);
   }

   if (sellCount > 0 && buyCount == 0) {
      OrderSend(Symbol(), OP_BUY, lot, Ask, 10, Ask - StopLoss * Point, Ask + TakeProfit * Point, "Hedge Buy", MagicNumber, 0, clrGreen);
   }
`;
  },

  hedgingFunctions() {
    return `
//+------------------------------------------------------------------+
//| Count orders by type                                             |
//+------------------------------------------------------------------+
int CountOrdersByType(int type) {
   int count = 0;
   for (int i = 0; i < OrdersTotal(); i++) {
      if (OrderSelect(i, SELECT_BY_POS, MODE_TRADES)) {
         if (OrderMagicNumber() == MagicNumber && OrderSymbol() == Symbol() && OrderType() == type)
            count++;
      }
   }
   return count;
}
`;
  },

  trendEntry(config) {
    return `
   // Trend Following Entry
   double lot = CalculateLot();
   if (CountOpenOrders() > 0) return;

   // MA Crossover check
   double maFast = iMA(Symbol(), PERIOD_CURRENT, 10, 0, MODE_EMA, PRICE_CLOSE, 1);
   double maSlow = iMA(Symbol(), PERIOD_CURRENT, 30, 0, MODE_EMA, PRICE_CLOSE, 1);
   double maFastPrev = iMA(Symbol(), PERIOD_CURRENT, 10, 0, MODE_EMA, PRICE_CLOSE, 2);
   double maSlowPrev = iMA(Symbol(), PERIOD_CURRENT, 30, 0, MODE_EMA, PRICE_CLOSE, 2);

   if (maFastPrev <= maSlowPrev && maFast > maSlow) {
      OrderSend(Symbol(), OP_BUY, lot, Ask, 10, Ask - StopLoss * Point, Ask + TakeProfit * Point, "Trend Buy", MagicNumber, 0, clrGreen);
   }

   if (maFastPrev >= maSlowPrev && maFast < maSlow) {
      OrderSend(Symbol(), OP_SELL, lot, Bid, 10, Bid + StopLoss * Point, Bid - TakeProfit * Point, "Trend Sell", MagicNumber, 0, clrRed);
   }
`;
  },

  trendFunctions() {
    return `// (uses CountOpenOrders from Grid strategy)`;
  },

  scalpingEntry(config) {
    return `
   // Scalping Entry
   double lot = CalculateLot();
   if (CountOpenOrders() > 3) return;

   double rsi = iRSI(Symbol(), PERIOD_M5, 14, PRICE_CLOSE, 0);

   if (rsi < 30) {
      OrderSend(Symbol(), OP_BUY, lot, Ask, 10, Ask - StopLoss * Point, Ask + TakeProfit * Point, "Scalp Buy", MagicNumber, 0, clrGreen);
   }

   if (rsi > 70) {
      OrderSend(Symbol(), OP_SELL, lot, Bid, 10, Bid + StopLoss * Point, Bid - TakeProfit * Point, "Scalp Sell", MagicNumber, 0, clrRed);
   }
`;
  },

  scalpingFunctions() {
    return `// (uses CountOpenOrders from Grid strategy)`;
  }
};